// LOOP UNTUK MEMPROSES RATUSAN EMAIL SEKALIGUS (V7)
const items = $input.all();
let results = [];

for (let i = 0; i < items.length; i++) {
  const j = items[i].json;
  const subject = j.subject || '';
  const snippet = j.snippet || '';

  const bodyBody = j.body || j.text || j.textPlain || '';
  const htmlBody = j.html || j.textHtml || '';

  let payloadText = '';
  if (j.payload) {
    const decode = (str) => {
      if (!str) return '';
      try {
        const b64 = str.replace(/-/g, '+').replace(/_/g, '/');
        return Buffer.from(b64, 'base64').toString('utf-8');
      } catch(e) { return ''; }
    };
    const walk = (p) => {
      let res = [];
      if (p.body && p.body.data) res.push(decode(p.body.data));
      if (p.parts) p.parts.forEach(part => res.push(walk(part)));
      return res.join(' ');
    };
    payloadText = walk(j.payload);
  }

  const combined = [subject, snippet, bodyBody, htmlBody, payloadText].join(' ');
  const cleanText = combined.replace(/<[^>]+>/g, ' ').replace(/\s+/g, ' ').trim();

  const priceRegex = /(?:Jumlah|Total|Rp|IDR)\s*[:\-\.]?\s*(?:Rp\.?|IDR)?\s*([\d.,]{3,})/gi;
  let nominal = 0;
  let m;
  while ((m = priceRegex.exec(cleanText)) !== null) {
    let n = m[1].replace(/\./g, '').replace(',', '.');
    if (m[1].includes(',') && m[1].includes('.')) n = m[1].replace(/\./g, '').replace(',', '.');
    else if (m[1].includes(',')) n = m[1].replace(/,/g, '.');
    const val = parseFloat(n);
    if (!isNaN(val) && val > 0) { nominal = val; break; }
  }

  const dateM = cleanText.match(/(\d{1,2})\s+(Jan|Feb|Mar|Apr|Mei|May|Jun|Jul|Agt|Aug|Sep|Okt|Oct|Nov|Des|Dec)[a-z]*\s+(\d{4})/i);
  const monthMap = { jan:'01', feb:'02', mar:'03', apr:'04', mei:'05', may:'05', jun:'06', jul:'07', agt:'08', aug:'08', sep:'09', okt:'10', oct:'10', nov:'11', des:'12', dec:'12' };

  let tang = new Date().toISOString();
  if (dateM) {
    const d = dateM[1].padStart(2, '0');
    const m = monthMap[dateM[2].toLowerCase().slice(0, 3)];
    const y = dateM[3];
    tang = `${y}-${m}-${d}T00:00:00+07:00`;
  }

  if (nominal > 0) {
      // LOGIKA TIPE: Sangat spesifik ke pola email Jago
      let tipe = 'debit';
      const isKredit = /Kamu menerima|Saldo kamu bertambah|Dana masuk|Transfer masuk|Top Up berhasil/i.test(subject);
      const isDebit = /Kamu telah membayar|Kamu telah melakukan|Kamu mengirimkan|Kamu memindahkan/i.test(subject);

      if (isKredit) tipe = 'kredit';
      else if (isDebit) tipe = 'debit';
      else {
        // Fallback ke body jika subject tidak jelas
        if (/kredit|penerimaan|terima transfer/i.test(cleanText) && !/membayar|mengirimkan|pembayaran/i.test(cleanText)) {
          tipe = 'kredit';
        }
      }

    results.push({
      json: {
        tanggal_waktu: tang,
        tipe,
        nominal,
        merchant_deskripsi: (cleanText.match(/Ke\s*[:\.]?\s*([A-Z ]{3,30})/i) || [0,'Unknown'])[1].trim(),
        kategori_otomatis: 'Lain-lain',
        email_subject: subject,
        raw_email_body: cleanText.slice(0, 500)
      }
    });
  }
}
return results;
